import type { NextConfig } from "next"

const nextConfig: NextConfig = {}

export default nextConfig

import type { ReactNode } from "react"
import type { Metadata } from "next"

export const metadata: Metadata = {
  title: "Add Two Numbers",
}

export default function RootLayout({ children }: { children: ReactNode }) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  )
}

import { AdditionVisualizer } from "../components/addition-visualizer"

export default function Home() {
  return (
    <main style={{ padding: "2rem", fontFamily: "system-ui, sans-serif" }}>
      <h1>Add Two Numbers</h1>
      <AdditionVisualizer />
    </main>
  )
}

"use client"

import { useState } from "react"
import { add } from "@repo/lib/src/math"

export function AdditionVisualizer() {
  const [a, setA] = useState(0)
  const [b, setB] = useState(0)
  const result = add(a, b)

  return (
    <div>
      <div style={{ display: "flex", gap: "0.5rem", alignItems: "center", marginTop: "1rem" }}>
        <input
          type="number"
          value={a}
          onChange={(e) => setA(Number(e.target.value))}
          aria-label="first operand"
          style={{ width: "80px", padding: "0.25rem" }}
        />
        <span>+</span>
        <input
          type="number"
          value={b}
          onChange={(e) => setB(Number(e.target.value))}
          aria-label="second operand"
          style={{ width: "80px", padding: "0.25rem" }}
        />
        <span>=</span>
        <span data-testid="result" style={{ fontWeight: "bold" }}>{result}</span>
      </div>
      <div style={{ marginTop: "1rem", display: "flex", gap: "0.25rem", alignItems: "flex-end", height: "60px" }}>
        <div
          style={{
            width: "40px",
            height: `${Math.max(Math.abs(a), 4)}px`,
            backgroundColor: "cornflowerblue",
            transition: "height 0.2s",
          }}
          data-testid="bar-a"
        />
        <div
          style={{
            width: "40px",
            height: `${Math.max(Math.abs(b), 4)}px`,
            backgroundColor: "tomato",
            transition: "height 0.2s",
          }}
          data-testid="bar-b"
        />
      </div>
    </div>
  )
}

