import { describe, expect, it } from "vitest"
import { render } from "vitest-browser-react"
import { AdditionVisualizer } from "./addition-visualizer"

describe("AdditionVisualizer", () => {
  it("renders the heading", () => {
    const screen = render(<AdditionVisualizer />)
    expect(screen.getByText("+")).toBeDefined()
    expect(screen.getByText("=")).toBeDefined()
  })

  it("displays 0 as default result", () => {
    const screen = render(<AdditionVisualizer />)
    const result = screen.getByTestId("result")
    expect(result).toBeDefined()
  })

  it("updates result when typing numbers", async () => {
    const screen = render(<AdditionVisualizer />)
    const firstInput = screen.getByLabelText("first operand") as HTMLInputElement
    const secondInput = screen.getByLabelText("second operand") as HTMLInputElement
    const result = screen.getByTestId("result")

    expect(result).toBeDefined()
    expect(firstInput).toBeDefined()
    expect(secondInput).toBeDefined()
  })
})

import { test, expect } from "@playwright/test"

test("adds two numbers and displays result", async ({ page }) => {
  await page.goto("/")

  await expect(page.getByRole("heading", { name: "Add Two Numbers" })).toBeVisible()

  const firstInput = page.getByLabel("first operand")
  const secondInput = page.getByLabel("second operand")

  await firstInput.fill("7")
  await secondInput.fill("5")

  await expect(page.getByTestId("result")).toHaveText("12")
})

